import json, glob
total = 0
for f in sorted(glob.glob('.step-io/*.output.jsonl')):
    for line in open(f):
        try:
            d = json.loads(line)
            u = d.get('params', {}).get('update', {})
            if u.get('sessionUpdate') == 'agent_message_chunk':
                c = u.get('content', {})
                if c.get('type') == 'text':
                    total += len(c.get('text', '').split())
        except:
            pass
print(json.dumps({'total_agent_words': total}))
